module top_module(
    Y ,
    A1,
    A2,
    B1,
    B2
);// Module ports
    output Y ;
    input  A1;
    input  A2;
    input  B1;
    input  B2;

    // Local signals
    wire nand0_out ;
    wire nand1_out ;
    wire and0_out_Y;

    //   Name   Output      Other arguments
    nand nand0 (nand0_out , A2, A1              );
    nand nand1 (nand1_out , B2, B1              );
    and  and0  (and0_out_Y, nand0_out, nand1_out);
    buf  buf0  (Y         , and0_out_Y          );

  always @(*) begin
    if (1'b0) begin
      if (A1 && A2) begin
        nand0_out <= 1'b0;
      end
      if (B1 && B2) begin
        nand1_out <= 1'b0;
      end
    end
  end

endmodule

